"use strict";(self.webpackChunkbcsd_blog=self.webpackChunkbcsd_blog||[]).push([[9893],{3727:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"/posts/introduce-PM-2025","metadata":{"permalink":"/product-manager/posts/introduce-PM-2025","source":"@site/@productManager/posts/introduce-PM-2025.mdx","title":"BCSD \uac00\uc774\ub4dc: PM","description":"PM \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","date":"2025-05-05T00:00:00.000Z","tags":[{"label":"PM","permalink":"/product-manager/tags/pm"},{"label":"\ud2b8\ub799 \uc18c\uac1c","permalink":"/product-manager/tags/\ud2b8\ub799-\uc18c\uac1c"}],"readingTime":5.92,"hasTruncateMarker":true,"authors":[{"name":"YoonWonBeen","url":"https://github.com/ONEBEAN7","email":"ywb0714@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/163230739?v=4","key":"ONEBEAN7"}],"frontMatter":{"date":"2025-05-05T00:00:00.000Z","authors":"ONEBEAN7","title":"BCSD \uac00\uc774\ub4dc: PM","description":"PM \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","keywords":["PM","\ud2b8\ub799 \uc18c\uac1c"],"tags":["PM","\ud2b8\ub799 \uc18c\uac1c"]},"unlisted":false,"nextItem":{"title":"\ub0a0 \uac83\uc758\xa0\ud3ec\ud150 : \ucf54\uc778 \uc2dd\ub2e8 \uae30\ud68d\uc758 \uc2dc\uc791","permalink":"/product-manager/LUNA-KK/rawpotential"}},"content":"PM \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!\\n\\n{/* truncate */}\\n\\n# **BCSD PM(\ud504\ub85c\ub355\ud2b8 \ub9e4\ub2c8\uc800) Track Introduce**\\n\\nPM \ud2b8\ub799\uc5d0 \uc9c0\uc6d0\ud574 \uc8fc\uc2e0 \uc5ec\ub7ec\ubd84, \ud658\uc601\ud569\ub2c8\ub2e4! \ud83d\udc4f\\n\\n\uc774 \ubb38\uc11c\ub294 PM(\ud504\ub85c\ub355\ud2b8 \ub9e4\ub2c8\uc800) \ud2b8\ub799\uc758 \uc804\ubc18\uc801\uc778 \uc18c\uac1c\uc640 \uc55e\uc73c\ub85c \uc5ec\ub7ec\ubd84\uc774 \uacbd\ud5d8\ud558\uac8c \ub420 \ub0b4\uc6a9\ub4e4\uc744 \ub2f4\uace0 \uc788\uc2b5\ub2c8\ub2e4. \ud55c \ubc88 \uaf2d \uc77d\uc5b4\ubcf4\uc2dc\uae38 \ucd94\ucc9c\ub4dc\ub9bd\ub2c8\ub2e4!\\n\\n---\\n\\n## **Q. PM\uc774\ub780 \ubb34\uc5c7\uc778\uac00\uc694?**\\n\\nPM(Product Manager, \ud504\ub85c\ub355\ud2b8 \ub9e4\ub2c8\uc800)\uc740 **\uc11c\ube44\uc2a4\ub098 \uc81c\ud488\uc758 \uae30\ud68d, \uc791\uc5c5 \uad00\ub9ac, \uadf8\ub9ac\uace0 \ud300 \ub0b4 \ub2e4\uc591\ud55c \uc5ed\ud560\uacfc\uc758 \uc18c\ud1b5 \ubc0f \ud611\uc5c5**\uc744 \ub2f4\ub2f9\ud569\ub2c8\ub2e4.\\n\\n\ub2e8\uc21c\ud788 \uc544\uc774\ub514\uc5b4\ub97c \ub0b4\ub294 \ub370 \uadf8\uce58\uc9c0 \uc54a\uace0, **\uc11c\ube44\uc2a4\uc758 \uae30\ud68d-\ub514\uc790\uc778-\uac1c\ubc1c** \ub4f1 \ub2e4\uc591\ud55c \ud504\ub85c\uc138\uc2a4\uc5d0 \ud3ed\ub113\uac8c \ucc38\uc5ec\ud558\uac8c \ub429\ub2c8\ub2e4.\\n\\n\uc6b0\ub9ac \ub3d9\uc544\ub9ac\uc5d0\uc11c\ub294 PM\uc774 \ud504\ub85c\uc81d\ud2b8 \uc804\uccb4\ub97c \ub9ac\ub529\ud558\ub294 \uc5ed\ud560\uc740 \uc544\ub2c8\uba70, \ud300\uc7a5\uacfc \ud611\ub825\ud558\uc5ec \uac01 \ud30c\ud2b8\uac00 \uc6d0\ud65c\ud788 \ud611\uc5c5\ud560 \uc218 \uc788\ub3c4\ub85d \ub3d5\ub294 \uc5ed\ud560\uc744 \uc218\ud589\ud569\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. PM\uc740 \ubb34\uc2a8 \uc77c\uc744 \ud558\ub098\uc694?**\\n\\n- **\uc11c\ube44\uc2a4 \uae30\ud68d \ubc0f \uc804\ub7b5 \uc218\ub9bd**\\n- **\uc2dc\uc7a5/\uc0ac\uc6a9\uc790 \uc870\uc0ac \ubc0f \uc694\uad6c\uc0ac\ud56d \ubd84\uc11d**\\n- **\ud504\ub85c\uc81d\ud2b8 \uc77c\uc815\uacfc \uc791\uc5c5 \uad00\ub9ac**\\n- **\uae30\ud68d-\ub514\uc790\uc778-\uac1c\ubc1c \uc804\ubc18\uc5d0 \uac78\uce5c \ud611\uc5c5 \ubc0f \ubb38\uc11c \uc791\uc131**\\n- **\ud300\uc6d0\ub4e4\uacfc\uc758 \uc18c\ud1b5 \ubc0f \ubb38\uc81c \uc815\uc758, \ud574\uacb0 \ubc29\ubc95 \uc81c\uc548**\\n- **\uc11c\ube44\uc2a4 \ucd9c\uc2dc \ud6c4 \ub370\uc774\ud130 \ubd84\uc11d \ubc0f \uac1c\uc120\uc548 \ub3c4\ucd9c**\\n\\nPM\uc740 \uc0ac\ud68c\uc5d0 \uc874\uc7ac\ud558\ub294 \ubb38\uc81c\ub97c \ud300\uc5d0 \uc788\ub294 \uac01 \uae30\ub2a5 \ub2f4\ub2f9\uc790(\uac1c\ubc1c\uc790, \ub514\uc790\uc774\ub108 \ub4f1)\uc640 \ud611\uc5c5\ud558\uc5ec \ud574\uacb0 \ubc29\ubc95\uc744 \uc81c\uc548\ud569\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. PM\uc5d0\uac8c \ud544\uc694\ud55c \uc5ed\ub7c9\uc740 \ubb34\uc5c7\uc778\uac00\uc694?**\\n\\nPM\uc740 \ub2e4\uc74c\uacfc \uac19\uc740 \uc5ed\ub7c9\uc774 \uc911\uc694\ud569\ub2c8\ub2e4.\\n\\n- **\ubb38\uc81c\ub97c \uc774\ud574\ud558\uae30 \uc704\ud55c \ubc30\uacbd \uc9c0\uc2dd**\\n- **\ud300\uc6d0\ub4e4\uacfc \uc6d0\ud65c\ud558\uac8c \uc18c\ud1b5\ud558\ub294 \uc18c\ud1b5 \uc5ed\ub7c9**\\n- **\ubb38\uc81c\ub97c \uc815\uc758\ud558\uace0 \ud574\uacb0\ucc45\uc744 \uc81c\uc2dc\ud558\ub294 \ubb38\uc81c \uc815\uc758 \ub2a5\ub825**\\n- **\ud611\uc5c5\uacfc \uc870\uc728 \ub2a5\ub825**\\n- **\ub17c\ub9ac\uc801 \uc0ac\uace0\uc640 \uae30\ud68d\ub825**\\n\\n\uc774\ub7ec\ud55c \uc5ed\ub7c9\uc744 \ubc14\ud0d5\uc73c\ub85c PM\uc740 \ub2e4\uc591\ud55c \ubc29\ubc95\uc73c\ub85c \ud504\ub85c\uc81d\ud2b8\uc5d0 \ucc38\uc5ec\ud569\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ube44\uae30\ub108\ub294 \uc5b4\ub5a4 \ub0b4\uc6a9\uc744 \ud559\uc2b5\ud558\uac8c \ub418\ub098\uc694?**\\n\\n\ube44\uae30\ub108 \uacfc\uc815\uc5d0\uc11c\ub294 \uc544\ub798\uc640 \uac19\uc740 \ub0b4\uc6a9\uc744 \ub2e8\uacc4\uc801\uc73c\ub85c \ubc30\uc6b0\uac8c \ub429\ub2c8\ub2e4.\\n\\n\uc790\uc138\ud55c \ucee4\ub9ac\ud058\ub7fc\uc740 [BCSD \ud648\ud398\uc774\uc9c0 PM \ud2b8\ub799](https://bcsdlab.com/track/product-manager)\uc5d0\uc11c \ud655\uc778\ud558\uc2e4 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n- **\ubb38\uc81c \uc815\uc758 \ubc0f \ud574\uacb0 \ubc29\ubc95 \uae30\ud68d**\\n    - \uc0ac\ud68c\ub098 \uc11c\ube44\uc2a4 \ub0b4\uc5d0\uc11c \ubc1c\uacac\ud55c \ubb38\uc81c\ub97c \uc815\uc758\ud558\uace0, \uc0c8\ub85c\uc6b4 \ud574\uacb0 \ubc29\ubc95\uc744 \uae30\ud68d\ud569\ub2c8\ub2e4.\\n- **\uae30\ud68d\uc11c \ubc0f \ubb38\uc11c \uc791\uc131\ubc95**\\n    - \uac1c\ubc1c\uc790, \ub514\uc790\uc774\ub108\uc640 \ud6a8\uacfc\uc801\uc73c\ub85c \ud611\uc5c5\ud560 \uc218 \uc788\ub3c4\ub85d, \uae30\ud68d \ub0b4\uc6a9\uc744 \uba85\ud655\ud558\uac8c \uc804\ub2ec\ud558\ub294 \ubb38\uc11c \uc791\uc131 \ubc29\ubc95\uc744 \ubc30\uc6c1\ub2c8\ub2e4.\\n- **\uc2dc\uc7a5 \uc870\uc0ac \ubc0f \uc0ac\uc6a9\uc790 \ubd84\uc11d**\\n    - \uc2dc\uc7a5 \ub3d9\ud5a5, \uacbd\uc7c1\uc0ac \ubd84\uc11d, \uc0ac\uc6a9\uc790 \ud398\ub974\uc18c\ub098 \ubc0f \uc720\uc800 \ud50c\ub85c\uc6b0 \uc124\uacc4 \ub4f1 \uc2e4\uc81c \uc11c\ube44\uc2a4 \uae30\ud68d\uc5d0 \ud544\uc694\ud55c \uc870\uc0ac \uae30\ubc95\uc744 \ud559\uc2b5\ud569\ub2c8\ub2e4.\\n- **\ud504\ub85c\uc81d\ud2b8 \uc6b4\uc601 \ubc29\ubc95\ub860**\\n    - \uc560\uc790\uc77c(Agile), \uc2a4\ud06c\ub7fc(Scrum) \ub4f1 \ud504\ub85c\uc81d\ud2b8\ub97c \ud6a8\uc728\uc801\uc73c\ub85c \uc6b4\uc601\ud558\ub294 \ubc29\ubc95\ub860\uc5d0 \ub300\ud574 \uacf5\ubd80\ud569\ub2c8\ub2e4.\\n- **\uae30\ucd08 \ub370\uc774\ud130 \ubd84\uc11d \ubc0f \uc11c\ube44\uc2a4 \uac1c\uc120**\\n    - \uc11c\ube44\uc2a4 \uc6b4\uc601 \ud6c4 \ub370\uc774\ud130\ub97c \ubd84\uc11d\ud558\uace0, \uc774\ub97c \ubc14\ud0d5\uc73c\ub85c \uac1c\uc120\uc548\uc744 \ub3c4\ucd9c\ud558\ub294 \ubc29\ubc95\uc744 \ubc30\uc6c1\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ud504\ub85c\uc81d\ud2b8\ub294 \uc5b4\ub5bb\uac8c \uc9c4\ud589\ub418\ub098\uc694?**\\n\\n- \ucd08\ubc18\uc5d0\ub294 **\uc544\uc774\ub514\uc5b4 \ub3c4\ucd9c**\uacfc **\ubb38\uc81c \uc815\uc758, \uae30\ud68d\uc11c \uc791\uc131** \uc2e4\uc2b5\uc744 \uc9c4\ud589\ud569\ub2c8\ub2e4.\\n- \uc774\ud6c4\uc5d0\ub294 \uc2e4\uc81c \ud300 \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c **\uae30\ud68d\uc790/PM \uc5ed\ud560**\ub85c \ucc38\uc5ec\ud558\uac8c \ub429\ub2c8\ub2e4.\\n- \ud504\ub85c\uc81d\ud2b8 \uc9c4\ud589 \uc911\uc5d0\ub294 **\ud300\uc6d0\ub4e4\uacfc \ud611\uc5c5, \uc77c\uc815 \ubc0f \uc791\uc5c5 \uad00\ub9ac, \ud68c\uc758 \uc9c4\ud589, \ud53c\ub4dc\ubc31 \uc218\uc9d1 \ubc0f \uac1c\uc120** \ub4f1 \uc2e4\ubb34\uc640 \uc720\uc0ac\ud55c \uacbd\ud5d8\uc744 \uc313\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- \ub2e8, \ud504\ub85c\uc81d\ud2b8 \uc804\uccb4\ub97c \ub9ac\ub529\ud558\ub294 \uc5ed\ud560\uc740 \ud300\uc7a5\uc774 \ub9e1\uace0, PM\uc740 \ud611\uc5c5\uacfc \uc870\uc728\uc5d0 \uc9d1\uc911\ud569\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ub808\uade4\ub7ec\ub85c \uc804\ud658\ub418\uba74?**\\n\\n\ube44\uae30\ub108 \uacfc\uc815\uc744 \uc131\uacf5\uc801\uc73c\ub85c \uc218\ub8cc\ud558\uba74,\\n\\nBCSD\uc758 \uc2e4\uc81c \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c **PM \uc5ed\ud560**\ub85c \ud22c\uc785\ub418\uc5b4\\n\\n\ub2e4\ub978 \ud2b8\ub799(\uac1c\ubc1c\uc790, \ub514\uc790\uc774\ub108 \ub4f1)\uacfc \ud611\uc5c5\ud558\uba70 \uc2e4\uc804 \uacbd\ud5d8\uc744 \uc313\uac8c \ub429\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \uc9c4\ub85c\ub294 \uc5b4\ub5bb\uac8c \ub418\ub098\uc694?**\\n\\nPM\uc740 IT \uc5c5\uacc4\uc5d0\uc11c \ub9e4\uc6b0 \uc911\uc694\ud55c \uc9c1\uad70\uc73c\ub85c,\\n\\n- **\uc2a4\ud0c0\ud2b8\uc5c5/\ub300\uae30\uc5c5 \uc11c\ube44\uc2a4 \uae30\ud68d\uc790**\\n- **\ud504\ub85c\uc81d\ud2b8 \ub9e4\ub2c8\uc800**\\n- **\ud504\ub85c\ub355\ud2b8 \uc624\ub108** \ub4f1 \ub2e4\uc591\ud55c \uae38\ub85c \uc9c4\ucd9c\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **\ub9c8\ubb34\ub9ac**\\n\\nPM \ud2b8\ub799\uc740 \u2018\uc0ac\ub78c\uacfc \uc11c\ube44\uc2a4, \uadf8\ub9ac\uace0 \ubb38\uc81c \ud574\uacb0\u2019\uc5d0 \uad00\uc2ec\uc774 \uc788\ub294 \ubd84\ub4e4\uaed8 \uc801\uadf9 \ucd94\ucc9c\ud569\ub2c8\ub2e4.\\n\\n\ubbf8\ub798\uc758 CEO \uc5ec\ub7ec\ubd84\ub4e4\uc744 \uae30\ub2e4\ub9ac\uace0 \uc788\uc5b4\uc694~"},{"id":"/LUNA-KK/rawpotential","metadata":{"permalink":"/product-manager/LUNA-KK/rawpotential","source":"@site/@productManager/LUNA-KK/rawpotential.mdx","title":"\ub0a0 \uac83\uc758\xa0\ud3ec\ud150 : \ucf54\uc778 \uc2dd\ub2e8 \uae30\ud68d\uc758 \uc2dc\uc791","description":"\uc62c\ud574 3\uc6d4, \ucf54\uc778 \uc2dd\ub2e8 \uae30\ud68d \uc5d0\ud53c\uc18c\ub4dc","date":"2024-08-25T00:00:00.000Z","tags":[{"label":"\ucf54\uc778","permalink":"/product-manager/tags/\ucf54\uc778"},{"label":"\uc2dd\ub2e8","permalink":"/product-manager/tags/\uc2dd\ub2e8"},{"label":"\uc0dd\ud611","permalink":"/product-manager/tags/\uc0dd\ud611"}],"readingTime":9.05,"hasTruncateMarker":true,"authors":[{"name":"somin","url":"https://github.com/LUNA-KK","email":"03somin0324@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/110970349?s=400&u=182536c247a9f6df9b88f33e7fb24cd23c0f3220&v=4","key":"LUNA-KK"}],"frontMatter":{"date":"2024-08-25T00:00:00.000Z","authors":"LUNA-KK","title":"\ub0a0 \uac83\uc758\xa0\ud3ec\ud150 : \ucf54\uc778 \uc2dd\ub2e8 \uae30\ud68d\uc758 \uc2dc\uc791","description":"\uc62c\ud574 3\uc6d4, \ucf54\uc778 \uc2dd\ub2e8 \uae30\ud68d \uc5d0\ud53c\uc18c\ub4dc","keywords":["\ucf54\uc778","\uc2dd\ub2e8","\ud68c\uace0"],"tags":["\ucf54\uc778","\uc2dd\ub2e8","\uc0dd\ud611"]},"unlisted":false,"prevItem":{"title":"BCSD \uac00\uc774\ub4dc: PM","permalink":"/product-manager/posts/introduce-PM-2025"},"nextItem":{"title":"\ub0b4\uac00 \uc0dd\uac01\ud558\ub294 BCSD Lab\uc5d0 \ub300\ud558\uc5ec","permalink":"/product-manager/yoonOneBeen/first-writing"}},"content":"{/* truncate */}\\n\\n\uc548\ub155\ud558\uc138\uc694. BCSD Lab\uc5d0\uc11c PM\uc73c\ub85c \ud568\uaed8\ud558\uace0 \uc788\ub294 \uae40\uc18c\ubbfc\uc785\ub2c8\ub2e4. FrontEnd \uac1c\ubc1c\ub85c \ucc38\uc5ec\ud558\ub2e4\uac00 \uc62c\ud574\ubd80\ud130 PM\uc73c\ub85c \ud65c\ub3d9\ud558\uac8c \ub418\uc5c8\uc5b4\uc694.\\n\\n\ucd5c\uadfc \uc81c Personal Branding\uc758 \ud55c \ubb38\uc7a5\uc744 \uaf3d\uc790\uba74 **_\uc5b4\ub5a4 \uacf3\uc5d0\uc11c\ub4e0 \uc790\uc2e0\uc758 \uae38\uc744 \ucc3e\uc544 \ub0a0 \uac83\uc758 \ud3ec\ud150\uc744 \ud130\ud2b8\ub9ac\ub294 \ub7ec\ub108_** \uc778\ub370\uc694. BCSD Lab\uc758 \uccab PM\uc73c\ub85c\uc11c \ub0b4\uac00 \uc798 \ud560 \uc218 \uc788\ub294, \ub098\ub9cc\uc758 \uc5ed\ud560\uc744 \uac70\uce68\uc5c6\uc774 \ucc3e\uc544\uac00\uace0 \uc788\uae30 \ub54c\ubb38\uc785\ub2c8\ub2e4.\\n\\n\u201c\uccab PM\u201d\uc774\ub77c\ub294 \uc77c\uc740 PM \uc5c6\uc774\ub3c4 \uc798 \uc791\ub3d9\ud558\ub358 \ud300\uc5d0 \ub07c\uc5b4\ub4e4\uc5b4 \uc228\uc5b4\uc788\ub358 \ud300\uc758 Pain Point\ub97c \ud574\uacb0\ud574\ub098\uac00\ub294 \uc77c\ub828\uc758 \uacfc\uc815\uc774\ub77c\ub294 \uc810\uc5d0\uc11c \uc11c\ube44\uc2a4 \ub0b4\uc758 PM\uc758 \uc5ed\ud560\uacfc\ub3c4 \ub2ee\uc544\uc788\ub294 \uac83 \uac19\uc2b5\ub2c8\ub2e4.\\n\\n\ub300\uac1c \uc2a4\ud0c0\ud2b8\uc5c5\uc758 PM\ub4e4\uc774 \uadf8\ub807\ub4ef \u201c\ub098\ub294 \uc5b4\ub5a4 \uc77c\uc744 \ud574\uc57c\ud560\uae4c?\u201d\uc758 \uc9c8\ubb38\uc744 \ub04a\uc784\uc5c6\uc774 \ub358\uc9c0\ub358, \uc62c\ud574 3\uc6d4\uc758 \uc774\uc57c\uae30\ub97c \ud480\uc5b4\ubcf4\ub824\ud569\ub2c8\ub2e4.\\n\\n![https://cdn-images-1.medium.com/max/1600/1*1jFAjiyswUJEvVxaMObiEA.png](https://cdn-images-1.medium.com/max/1600/1*1jFAjiyswUJEvVxaMObiEA.png)\\n\\nSprint\xa0:\xa0\uc804\ub825\uc9c8\uc8fc\ud558\ub2e4\\n\\n### \ud559\uc0dd\ucc98\uc7a5\ub2d8\uacfc\uc758 \ub9cc\ub0a8\\n\\n> \uc18c\ubbfc\ud559\uc0dd\uc740 \ud558\ub294 \uc77c\uc774 \uc815\ub9d0 \ub9ce\ub124\uc694\\n\\n\uc9c0\ub09c 3\uc6d4 11\uc77c, \ud559\uc0dd\ucc98\uc7a5\ub2d8\uaed8\uc11c \uad50\ub0b4 \uce74\ud398 \u2018\ub300\uc990\u2019\uc758 \ubc30\ub2ec \uc11c\ube44\uc2a4\ub97c \uc81c\uc548\ud574\uc8fc\uc168\ub294\ub370\uc694. \uc6b0\uc5f0\ud788 \uc774\ub9ac\uc800\ub9ac \ub9c8\uc8fc\uce58\uba70, \uc800\ub97c \ud558\ub294 \uc77c \ub9ce\uc740 \ud559\uc0dd\uc73c\ub85c \uae30\uc5b5\ud574\uc8fc\uc168\ub358, \uc815\ub9d0 \uc874\uacbd\ud558\ub294 \ucc98\uc7a5\ub2d8\uc758 \uc5f0\ub77d\uc5d0 \uc815\ub9d0 \ubc18\uac00\uc6e0\ub358 \uae30\uc5b5\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ubc30\ub2ec \uc11c\ube44\uc2a4\ub294 \ubc30\ub2ec \uc0ac\uace0 \ub4f1\uc758 \ub9ac\uc2a4\ud06c\ub85c \uc778\ud574 \ubb34\uc0b0\ub418\uc5c8\uc9c0\ub9cc, \uc774\ub97c \uae30\ud68c\uc0bc\uc544 \u2018\ucf54\uc778\'\uc758 \uc2dd\ub2e8 \uae30\ub2a5\uc744 \uc81c\uc548\ub4dc\ub9b4 \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\uc81c\uc548\ub4dc\ub9b0 \ub0b4\uc6a9\uc740 **\uc2dd\ub2e8 \uc0ac\uc9c4**\uacfc **\ud488\uc808 \uc54c\ub9bc**\uc774\uc5c8\ub294\ub370, \uae30\uc874\uc5d0 \uc2dd\ub2e8\uc744 \uc5c5\ub85c\ub4dc\ud558\ub358 \uc0dd\ud611 \ud648\ud398\uc774\uc9c0\ub97c \u2018\ucf54\uc778\u2019\uc73c\ub85c \ub300\uccb4\ud558\uace0, \uad50\ub0b4 \ud648\ud398\uc774\uc9c0\ub97c \ud1b5\ud574 \ub9ac\ub2e4\uc774\ub809\ud2b8 \ud560 \uc218 \uc788\ub3c4\ub85d \ud611\uc758\ud558\uc600\uc2b5\ub2c8\ub2e4.\\n\\n### \uacc4\ud68d\uc744 \ub530\ub974\uae30\ubcf4\ub2e4 \ubcc0\ud654\uc5d0\xa0\ub300\uc751\ud558\uae30\ub97c\\n\\n**: \uc560\uc790\uc77c \uc18c\ud504\ud2b8\uc6e8\uc5b4 \uac1c\ubc1c \uc120\uc5b8**\\n\\n\uad50\ub0b4 \ud648\ud398\uc774\uc9c0\ub294 \ub300\ubd80\ubd84\uc758 \ud559\uc0dd \ubc0f \uad50\uc9c1\uc6d0\uc774 \uc2dd\ub2e8\uc744 \ud655\uc778\ud558\ub294 \uacf3\uc774\uae30\uc5d0 \ubd80\ud47c \ub9c8\uc74c\uc744 \uc548\uace0 \ud300\uc6d0\ub4e4\uacfc \uc2a4\ud504\ub9b0\ud2b8\ub97c \uc9c4\ud589\ud558\uace0 \uc788\uc5c8\uc2b5\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \ub2e4\uc74c \ubbf8\ud305\uc5d0\uc11c **\uc0dd\ud611 \ud648\ud398\uc774\uc9c0\uac00 EOS\ub418\uace0 \uc2dd\ub2e8 \uc5c5\ub85c\ub4dc \ud50c\ub7ab\ud3fc \uc790\uccb4\uac00 \ubcc0\uacbd\ub41c\ub2e4\ub294 \ud1b5\ubcf4**\ub97c \ubc1b\uac8c \ub418\uc5c8\uc2b5\ub2c8\ub2e4. \ubcf4\uc548\uc0c1\uc758 \uc774\uc720\ub85c \uc678\ubd80 \uc0ac\uc774\ud2b8\uc778 \u2018\ucf54\uc778\'\uc73c\ub85c \ub9ac\ub2e4\uc774\ub809\ud305 \ud560 \uc218 \uc5c6\uc73c\uba70, \uae30\uc874\uc758 \u2018\ucf54\uc778\' \uc2dd\ub2e8 \ud06c\ub864\ub9c1 \ubc29\uc2dd \ubcc0\uacbd\uacfc \ub354\ubd88\uc5b4 \uc601\uc591\uc0ac\ub2d8\uc758 \uc628\ubcf4\ub529 \uae30\uac04\uae4c\uc9c0 \ubb34\uae30\ud55c \ub300\uae30\ud574\uc57c\ud55c\ub2e4\ub294 \uac83\uc785\ub2c8\ub2e4.\\n\\n\ud559\uad50 \uce21\uc5d0\uc11c \uc81c\uc548\uc8fc\uc2e0 \ub0b4\uc6a9\uc740 \uc601\uc591\uc0ac \uc120\uc0dd\ub2d8\uaed8\uc11c \uc2dd\ub2e8 \uc5d1\uc140 \ud30c\uc77c\uc744 \uad50\ub0b4 \ud50c\ub7ab\ud3fc, \ucf54\uc778 \ub450\uacf3\uc5d0 \uc5c5\ub85c\ub4dc\ud558\ub294 \uac83\uc774\uc5c8\ub294\ub370\uc694. \uc2dd\ub2e8 \ub0b4\uc6a9\uc744 \uacf5\uac1c \ub370\uc774\ud130\ub85c \uc81c\uacf5\ud558\ub294 \uac83\uc774 \ud569\ub9ac\uc801\uc774\ub77c\ub294 \uc0dd\uac01\uc774 \ub4e4\uc5b4 \uc870\uc2ec\uc2a4\ub808 \uba54\uc77c\uc744 \ubcf4\ub0b4\ubcf4\uc558\uc2b5\ub2c8\ub2e4.\\n\\n![https://cdn-images-1.medium.com/max/1600/1*ck_08F2HaROEmhDwj_H8ww.png](https://cdn-images-1.medium.com/max/1600/1*ck_08F2HaROEmhDwj_H8ww.png)\\n\\n\ucc98\uc7a5\ub2d8\uaed8\uc11c \ud569\ub9ac\uc801\uc778 \uc758\uacac\uc774\ub77c\uba70 \uae0d\uc815\uc801\uc73c\ub85c \uac80\ud1a0\ud574\uc8fc\uc2dc\uae38 \ub9d0\uc500\ub4dc\ub838\uc73c\ub098, \ud559\uad50 \uce21\uc5d0\uc11c\ub3c4 \uc5ec\ub7ec \ub3c4\uba54\uc778\uacfc \uad50\uc9c1\uc6d0 \ubd84\ub4e4\uc774 \uc5ee\uc5ec\uc788\uc5b4 \ub17c\uc758\uac00 \ud55c\ucc38\uc744 \ubbf8\ub904\uc9c0\ub354\ub2c8 \uacb0\uad6d\uc740 \ube44\uc6a9\ubb38\uc81c\ub85c \ubb34\uc0b0\ub418\uace0 \ub9d0\uc558\uc2b5\ub2c8\ub2e4.\\n\\n\uacb0\uad6d\uc5d4 \ub178\uc2ec\ucd08\uc0ac\ud558\uba70 \uc2dd\ub2e8 \ud50c\ub7ab\ud3fc \ubcc0\uacbd \uc720\ubb34\ub97c \ud655\uc778\ud558\uace0 **\ud06c\ub864\ub9c1\uc744 \ub300\ube44**\ud588\uc73c\uba70, **\uc601\uc591\uc0ac\ub2d8\uc758 \ubcc0\uacbd\ub418\ub294 \uc694\uad6c\uc0ac\ud56d\uc5d0 \ub300\ud574 \uc9c0\uc18d\uc801\uc73c\ub85c \ub300\uc751**\ud558\uc600\uc2b5\ub2c8\ub2e4.\\n\\n![https://cdn-images-1.medium.com/max/1600/1*Omt1oXDj-tDh8AUSpTKAvg.png](https://cdn-images-1.medium.com/max/1600/1*Omt1oXDj-tDh8AUSpTKAvg.png)\\n\\n\uc0dd\ud611 \uc9c1\uc6d0\ubd84\ub4e4\uacfc \uc9c4\ud589\ud55c\xa0\ubbf8\ud305\\n\\n\uadf8\ub807\uac8c *\ud559\uc0dd\ucc98\uc7a5\ub2d8*\uc744 \ube44\ub86f\ud55c _\uc0dd\ud611 \uc601\uc591\ud300\uc7a5\ub2d8, \uc0dd\ud611 \uc601\uc591\uc0ac\ub2d8, \ucd1d\ubb34\ub2d8, \uc778\ud504\ub77c \ud300\uc7a5\ub2d8_ \ub4f1\uc758 \uad50\uc9c1\uc6d0\ubd84\ub4e4\uacfc 6\ud68c \uac00\ub7c9\uc758 \ubbf8\ud305\uc744 \uc9c4\ud589\ud558\uace0 **\uc11c\ube44\uc2a4\uac00 \ubc30\ud3ec\ub41c\uc9c0 \ud55c \ub2ec \uc5ec\ub9cc\uc778 6\uc6d4 10\uc77c\uc5d0 \ube44\ub85c\uc18c \uae30\ub2a5\uc744 \uac8c\uc2dc**\ud560 \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n![https://cdn-images-1.medium.com/max/1600/1*9-rd3f2q6xunv0H3osrIaA.png](https://cdn-images-1.medium.com/max/1600/1*9-rd3f2q6xunv0H3osrIaA.png)\\n\\n\ub0b4\uac00 \ub9cc\ub4e0 \ubaa9\uc5c5\uacfc \uce74\ub4dc\ub274\uc2a4\uac00 \ud559\uad50 \uacf5\uc2dd \uc778\uc2a4\ud0c0 \uacf3\uacf3\uc5d0 \uc5c5\ub85c\ub4dc\xa0\ub418\uc5c8\ub2e4\\n\\n\ud300\uc6d0\ub4e4\uc774 \uc815\ub9d0 \uc5f4\uc2ec\ud788 \uc2a4\ud504\ub9b0\ud2b8\ub97c \ub2ec\ub824\uc900 \ub9cc\ud07c \uc870\uae08\uc774\ub77c\ub3c4 \ube68\ub9ac \uc11c\ube44\uc2a4\ub97c \ucd9c\uc2dc\ud558\uae30 \uc704\ud574 \ub2e4\ubc29\uba74\uc73c\ub85c \ubb38\uc744 \ub450\ub4dc\ub9ac\ub294 \uc2dc\uac04\ub4e4\uc774\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n![https://cdn-images-1.medium.com/max/1600/0*PKmECD6yxkXBX6yh.jpg](https://cdn-images-1.medium.com/max/1600/0*PKmECD6yxkXBX6yh.jpg)\\n\\nOkay\u2026\u2026\u2026Bye\u2026\u2026\u2026\u2026\u2026\\n\\n### Cross-functional person\xa0\ud83d\ude4b\u200d\u2640\\n\\n\uae30\ub2a5 \uac8c\uc2dc \uc5f0\uae30 \ubc0f \ub514\uc790\uc774\ub108 \ub9ac\uc18c\uc2a4 \ubd80\uc871\uc73c\ub85c \ud300\uc6d0\ub4e4\uc758 \uac1c\ubc1c \uc758\uc695\uc774 \ub2e4\uc18c \ub5a8\uc5b4\uc9c4 \uc0c1\ud0dc\uc600\uae30\uc5d0, \ub3c4\uba54\uc778 \uc560\uc815\ub3c4\uc640 \uc0ac\uae30 \uc99d\uc9c4\uc744 \uc704\ud574 \ub9c8\ucf00\ud305\uc744 \ub354 \uc801\uadf9\uc801\uc73c\ub85c \uc9c4\ud589\ud588\ub294\ub370\uc694.\\n\\n\uc57d \ud55c \ub2ec\uac04 **\uad50\ub0b4 \uc2e0\ubb38\uc0ac \uc778\ud130\ubdf0, \ud64d\ubcf4 \ud3ec\uc2a4\ud130 \ubd80\ucc29, \uc5d0\ube0c\ub9ac\ud0c0\uc784 \ubc0f \uc778\uc2a4\ud0c0\uadf8\ub7a8 \ud64d\ubcf4, \ubaa9\uc5c5 \ubc0f \uce74\ub4dc\ub274\uc2a4 \uc81c\uc791, \ub274\uc2a4 \uae30\uc0ac \uc778\ud130\ubdf0, \ud559\uad50 \uacf5\uc2dd \uc778\uc2a4\ud0c0\uadf8\ub7a8 \uc778\ud130\ubdf0, \uad50\ub0b4 \uacf5\uc2dd \ube14\ub85c\uadf8, \uad50\ub0b4 \uc628\ub77c\uc778 \ud64d\ubcf4\ub300\uc0ac \ube14\ub85c\uadf8** \ub9c8\ucf00\ud305\uc744 \uc9c4\ud589\ud588\uc2b5\ub2c8\ub2e4.\\n\\n\uc9c0\uc18d\uc801\uc73c\ub85c \uc5f0\ub77d\uc744 \uc774\uc5b4\uac00\ub358 \ud559\uc0dd\ucc98\uc7a5\ub2d8\uacfc \ud3c9\uc18c \uce5c\ubd84\uc774 \uc788\ub358 \ud64d\ubcf4\ud300 \uc120\uc0dd\ub2d8, \ud64d\ubcf4 \uad00\ub828 \uc791\uc5c5\uc744 \ud558\ub294 \uc9c0\uc778\ubd84\ub4e4\uc774 \uc788\uc5c8\uae30\uc5d0 \uac00\ub2a5\ud588\ub358 \uc77c\uc774\uc5c8\ub358 \uac83 \uac19\uc2b5\ub2c8\ub2e4. \uc81c\uac00 \ub514\uc790\uc778\ud55c \uce74\ub4dc\ub274\uc2a4\ub97c \ud559\uad50 \uacf5\uc2dd SNS \uacc4\uc815\uc5d0\ub3c4 \uc5c5\ub85c\ub4dc\ud558\uace0, \ub274\uc2a4 \uae30\uc0ac\uc5d0\ub3c4 \uc62c\ub77c\uac00\ub294 \ub098\ub984 \uc2e0\uc120\ud55c \uacbd\ud5d8\uc774 \ub418\uc5c8\uc2b5\ub2c8\ub2e4.\\n\\n\uc9c4\ud589\ub41c \ub0b4\uc6a9\uc740 \uc544\ub798 \ub9c1\ud06c\uc5d0\uc11c \ud655\uc778\ud558\uc2e4 \uc218 \uc788\uc2b5\ub2c8\ub2e4! \uc5c4\ub9c8 \ub098 \ub274\uc2a4 \ub098\uc654\uc5b4~\\n\\n- [\ucda9\uccad\uc77c\ubcf4](https://www.ccdailynews.com/news/articleView.html?idxno=2279838)\\n- [\ucda9\uccad\uc2e0\ubb38](https://www.dailycc.net/news/articleView.html?idxno=790821)\\n- [\ub514\ud2b8\ub274\uc2a4 24](https://www.dtnews24.com/news/articleView.html?idxno=773623)\\n- [\uad7f\ubaa8\ub2dd \ucda9\uccad](https://www.goodmorningcc.com/news/articleView.html?idxno=311478)\\n- [\ub85c\uceec\ud22c\ub370\uc774](https://www.localtoday.co.kr/news/articleView.html?idxno=303893)\\n- [\ub274\uc2a4\uc138\uc0c1](https://www.newssesang.kr/news/articleView.html?idxno=260514)\\n- [\uc0dd\ud65c\uad00\ud611\ub3d9\uc870\ud569 \uc778\uc2a4\ud0c0\uadf8\ub7a8](https://www.instagram.com/p/C8XwUYiStXl/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA%3D%3D)\\n- [\ud55c\uad6d\uae30\uc220\uad50\uc721\ub300\ud559\uad50 \ubc30\ub108](https://www.koreatech.ac.kr/gallery.es?mid=a10701010000&bid=0017&list_no=51788&act=view)\\n- [\uad50\ub0b4 \uacf5\uc2dd \uc778\uc2a4\ud0c0\uadf8\ub7a8 \uc778\ud130\ubdf0](https://www.instagram.com/p/C8d_g5nShei/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA%3D%3D&img_index=1)\\n- [\ud559\uad50 \uacf5\uc2dd \ube14\ub85c\uadf8](https://m.blog.naver.com/PostView.naver?blogId=koreatech91&logNo=223486974367&navType=by)\\n- [\uad50\ub0b4 \uc628\ub77c\uc778 \ud64d\ubcf4\ub300\uc0ac \ube14\ub85c\uadf8](https://blog.naver.com/koreatech91/223492789781)\\n\\n![https://cdn-images-1.medium.com/max/800/1*QfPX-dYtd2vVBW_m8bS6KQ.png](https://cdn-images-1.medium.com/max/800/1*QfPX-dYtd2vVBW_m8bS6KQ.png)\\n\\n![https://cdn-images-1.medium.com/max/2000/1*0KxZrtwlh0ofAbXpRuj4Mg.png](https://cdn-images-1.medium.com/max/2000/1*0KxZrtwlh0ofAbXpRuj4Mg.png)\\n\\n### \ud30c\ub3c4\uac00 \uce60\ub54c\ub294\xa0\uc11c\ud551\uc744\\n\\n\ub514\uc790\uc778\ubd80\ud130 \ub9c8\ucf00\ud305\uae4c\uc9c0 \uc544\ubb34\ub3c4 \ud558\uc9c0 \uc54a\ub294 \uc791\uc5c5\ub4e4\uc744 \ub3c4\ub9e1\uc544\ud558\uba70 \uc774\uac8c \ub098\uc758 \uc131\uc7a5\uc5d0 \ub3c4\uc6c0\uc774 \ub418\ub294 \uc77c\uc778\uc9c0 \uace0\ubbfc\uc5d0 \ube60\uc9c0\uae30\ub3c4 \ud588\uc9c0\ub9cc, \ud300\uacfc \ub3c4\uba54\uc778\uc5d0 \ub300\ud55c \uc560\uc815\uc73c\ub85c \ub2ec\ub9b4 \uc218 \ubc16\uc5d0 \uc5c6\uc5c8\ub358 \uac83 \uac19\uc2b5\ub2c8\ub2e4.\\n\\n\uc678\ubd80\uc758 \uace0\uac1d\uacfc \uc9c0\uc18d\uc801\uc73c\ub85c \uc18c\ud1b5\ud558\uba70 **\ud569\ub9ac\uc801\uc778 \ud611\ub825\ubc29\uc548\uc744 \ucc3e\uc73c\ub824 \ub2e4\ubc29\uba74\uc73c\ub85c \ub178\ub825**\ud558\uba70, **\uacc4\ud68d\uc744 \ub530\ub974\uc9c0\ub3c4 \ubabb\ud558\uace0 \ubcc0\ud654\uc5d0 \ub300\uc751**\ud560 \uc218 \ubc16\uc5d0 \uc5c6\ub294 \uc0c1\ud669\uc774 \ub2e5\uce58\uae30\ub3c4 \ud588\uc9c0\ub9cc, [\uc560\uc790\uc77c \uc18c\ud504\ud2b8\uc6e8\uc5b4 \uac1c\ubc1c \uc120\uc5b8](https://agilemanifesto.org/iso/ko/manifesto.html)\uc744 \ub9c8\uc74c\uc5d0 \uc0c8\uae30\uba70 \uc720\uc5f0\ud55c \ub300\uc751\uc744 \ubc30\uc6b0\ub294 \uc2dc\uac04\uc774 \ub418\uae30\ub3c4 \ud588\uc2b5\ub2c8\ub2e4.\\n\\n\ucd5c\uadfc\uc5d0\ub3c4 \ub514\uc790\uc774\ub108 \ub9ac\uc18c\uc2a4 \ubd80\uc871\uc5d0 \ub300\uc751\ud558\ub294 \ubc95\uc5d0 \ub300\ud574 \uace0\ubbfc\ud558\uba70 \ub2e4\uc591\ud55c \ubcc0\uc218\uc5d0 \uc720\uc5f0\ud558\uac8c \ub300\ucc98\ud574\ubcfc \uc218 \uc788\ub294 \uc88b\uc740 \uc11c\ud551 \uc5f0\uc2b5\uc744 \ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc5f0\ubd09\ud611\uc0c1 \uc5c6\ub294 \uc2e0\uc785\uc758 \ud328\uae30, \ubc30\uace0\ud508 \ub300\ud559\uc0dd\uc758 \ud3ec\ud150\uc744 \ud130\ud2b8\ub9ac\ub294 \uadf8\ub0a0\uae4c\uc9c0~!! \ub2ec\ub824\ubcf4\uaca0\uc2b5\ub2c8\ub2e4~"},{"id":"/yoonOneBeen/first-writing","metadata":{"permalink":"/product-manager/yoonOneBeen/first-writing","source":"@site/@productManager/yoonOneBeen/first-writing.mdx","title":"\ub0b4\uac00 \uc0dd\uac01\ud558\ub294 BCSD Lab\uc5d0 \ub300\ud558\uc5ec","description":"PM \ud0ed\uc5d0 \uc624\uc2e0 \uac78 \ud658\uc601\ud569\ub2c8\ub2e4.","date":"2024-04-04T00:00:00.000Z","tags":[{"label":"PM","permalink":"/product-manager/tags/pm"}],"readingTime":5.655,"hasTruncateMarker":true,"authors":[{"name":"YoonWonBeen","url":"https://github.com/ONEBEAN7","email":"ywb0714@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/163230739?v=4","key":"ONEBEAN7"}],"frontMatter":{"date":"2024-04-04T00:00:00.000Z","authors":"ONEBEAN7","title":"\ub0b4\uac00 \uc0dd\uac01\ud558\ub294 BCSD Lab\uc5d0 \ub300\ud558\uc5ec","description":"PM \ud0ed\uc5d0 \uc624\uc2e0 \uac78 \ud658\uc601\ud569\ub2c8\ub2e4.","keywords":["BCSD","\ud68c\uace0","PM"],"tags":["PM"]},"unlisted":false,"prevItem":{"title":"\ub0a0 \uac83\uc758\xa0\ud3ec\ud150 : \ucf54\uc778 \uc2dd\ub2e8 \uae30\ud68d\uc758 \uc2dc\uc791","permalink":"/product-manager/LUNA-KK/rawpotential"}},"content":"BCSD Blog\uc758 \ud0c4\uc0dd\uc744 \uae30\ub150\ud558\uba70,\\n\\n{/* truncate */}\\n\uc624\ub298 \ub098\ub294 BCSD Blog\uc758 \ud0c4\uc0dd\uc744 \uae30\ub150\ud558\uc5ec, \ud55c\uae30\ub300\uc5d0\uc11c\ub3c4, \ucef4\ud4e8\ud130 \uacf5\ud559 \uc804\uacf5\uc5d0\uc11c\ub3c4 \uc678\ubd80\uc778\uc778 \ub0b4\uac00 \ubc14\ub77c\ubcf4\ub294 BCSD Lab\uc758 \ubaa8\uc2b5\uc744 \uae30\ub85d\ud574 \ubcf4\ub824\uace0 \ud55c\ub2e4.\\n\\n## BCSD Lab\uc758 \uccab\uc778\uc0c1\uacfc \ub098\uc758 \uc774\uc57c\uae30\\n\\nBCSD Lab\uc5d0 \ub300\ud574\uc11c \ucc98\uc74c \ub4e3\uac8c \ub41c \uac83\uc740 2020\ub144\ub300 \ucd08\uc758 \uc77c\uc774\uc5c8\ub2e4. ~~\uc9c0\uae08\uc740 \uc5bc\uad74\ub3c4 \ubcf4\uae30 \ud798\ub4e4 \uc815\ub3c4\ub85c \uba40\uc5b4\uc9c4~~ \uce5c\uad6c\uac00 \uc790\uae30\uac00 \uac00\uc785\ud55c \ub3d9\uc544\ub9ac\uc5d0 \ub300\ud574 \uc774\uc57c\uae30\ud574 \uc8fc\uc5c8\ub2e4. \ucef4\uacf5\uacfc\uc778 \uadf8\ub294, \uc790\uc2e0\uc774 \uc0c1\ub2f9\ud788 \uc218\uc900 \ub192\uc740 \ub3d9\uc544\ub9ac\uc5d0\uc11c \ud65c\ub3d9\ud558\uace0 \uc788\ub2e4\uace0 \ud588\ub2e4. \uadf8\ub294 \ub0b4\uac00 \uc54c\uae30\ub85c \uc608\uc804\ubd80\ud130 \uc2e4\uc804\uc5d0 \ud65c\uc6a9\ud560 \uc218 \uc788\ub294 \uc0dd\uc0dd\ud55c \uc9c0\uc2dd\uc744 \ud0d0\uad6c\ud558\uace0 \uc131\uc7a5\ud558\ub824\ub294 \uc695\uad6c\uac00 \uc788\uc5c8\ub2e4. \uadf8\uac00 \ub4e4\uc5b4\uac04 \ub3d9\uc544\ub9ac\ub77c, \uaf64 \uad1c\ucc2e\uc740 \ub3d9\uc544\ub9ac\uc774\uaca0\ub2e4. \uc0dd\uac01\ud588\ub2e4.\\n\\n\ub0b4\uac00 \uc774\ud574\ud55c \ub0b4\uc6a9\uc740 \uadf8\uc758 \uc790\ub791\ubcf4\ub2e4 \uc5c4\uccad\ub0ac\ub2e4. \uae4c\ub9c8\ub4dd\ud55c \uc120\ubc30\ub2d8\ub4e4\uaed8\uc11c \ub9cc\ub4dc\uc2e0 \ub3d9\uc544\ub9ac, \uc2e4\uc804\uc801\uc778 \uad50\uc721\uc744 \ud1b5\ud574 \uba64\ubc84\ub85c \ub9cc\ub4dc\ub294 \ud6c8\ub828, \uc2e4\uc81c\ub85c \ud559\uc0dd\ub4e4\uc5d0\uac8c \ub3c4\uc6c0\uc774 \ub418\ub294 \uc11c\ube44\uc2a4\ub97c \uc81c\uacf5\ud558\uace0 \uc788\ub294 \uc120\ud6c4\ubc30\ub85c \uc774\ub8e8\uc5b4\uc9c4 \uc7ac\ud559\uc0dd \uc870\uc9c1, \uba64\ubc84\ub85c \ucc38\uc5ec\ud558\uc5ec \ucf54\ub4dc \ud55c \uc904 \ud55c \uc904 \uae30\uc5ec\ud560 \uc218 \uc788\ub294 \ubc1c\ud310. \uc774 \ub9d0\uc744 \ub4e3\uac8c \ub41c \ub098\ub294 \uace0\ubb34\ub418\uc5c8\ub358 \uac83 \uac19\ub2e4.\\n\\n\uadf8\ub7ec\ud55c \uc790\uadf9\uc758 \uc911\uc2ec\uc5d0\ub294 \ud559\uad50 \ud559\uacfc\uc5d0 \uc5fc\uc99d\uc744 \ub290\ub07c\ub358 \ub0b4\uac00 \uc788\uc5c8\ub2e4. \ub2e4\ub978 \ubb38\uc81c\uac00 \uc544\ub2c8\uc5c8\ub2e4. \ub0b4\uac00 \uad70 \ubcf5\ubb34\ub97c \ud558\ub294 \ub3d9\uc548\uc5d0 \ud2b9\uc815 \uc0b0\uc5c5\uc744 \uc5f0\uad6c\ud558\ub294 \uc6b0\ub9ac \ud559\uacfc\ub294, \ud589\uc815\uacfc\uc640 \ubcd1\ud569\ub418\uba70 \ub0b4\uac00 \ud55c \ubc88\ub3c4 \ubc30\uc6b8 \uac83\uc774\ub77c \uc0dd\uac01\ub3c4 \ud55c \uc801 \uc5c6\ub294 \uc804\uacf5\uacfc \ud569\uccd0\uc838\uc11c \ud559\ubd80\ub85c \ubc14\ub00c\uc5b4 \uc788\uc5c8\ub2e4. \ud568\uaed8 \uc0b0\uc5c5\ud559\uacfc\ub85c \uc628 \ub3d9\uae30\ub4e4 \ub9c8\uc800\ub3c4, \ubb34\ub825\ud558\uac8c \ud589\uc815\uacfc \ucde8\uc9c1\uc73c\ub85c \ubc1c\uae38\uc744 \ub3cc\ub838\ub2e4.\\n\\n\ub098\ub294 \uc774\ub7f0 \ub3d9\uc544\ub9ac\uac00 \uc6b0\ub9ac \ud559\uad50\uc5d0\ub3c4 \uc788\uc5c8\ub2e4\uba74 \ud558\uace0 \ubc14\ub790\ub2e4. \uadf8\ub7ec\ub098 \uc6b0\ub9ac \uacfc \ud559\uc0dd\ub4e4\uc774 \ub0b4 \ub9d0\uc744 \uadc0 \uae30\uc6b8\uc774\uae30\uc5d4, \ub108\ubb34 \ubc14\uc058\uace0 \uae4c\ub9c8\ub4dd\ud55c \uc120\ubc30\ub4e4\uacfc, \uc870\uc6a9\ud788 \uc0b4 \uae38\uc744 \ucc3e\uc544 \ube60\uc838\ub098\uac00\ub294 \ub3d9\uae30\ub4e4, \ubbf8\ub798\uc5d0 \ub300\ud55c \uace0\ubbfc\ubfd0\uc778 \ud6c4\ubc30\ub4e4\ub9cc\uc774 \uc788\uc5c8\ub2e4.\\n\\n(\uc2e4\uc81c\ub85c \ub098\ub294 \uc791\uc740 \uc18c\ubaa8\uc784\uc744 \ubaa8\uc9d1\ud558\ub824 \ud588\uc9c0\ub9cc, \uc778\uc6d0\uc740 \ubaa8\uc774\uc9c0 \uc54a\uc558\ub2e4.)\\n\\n## BCSD Lab\\n\\n\ub098\ub294 \ud604\uc7ac \uc774\uacf3\uc5d0\uc11c \ud6cc\ub96d\ud55c \uba64\ubc84\ub4e4\uc5d0\uac8c \ub9ce\uc740 \ubc30\uc6c0\uc744 \ubc1b\uace0 \uc788\ub2e4. \ud559\ubc88\uc5d0 \uad6c\uc560\ub418\uc9c0 \uc54a\uace0 \ubaa8\ub450\uac00 \uc758\uacac\uc744 \uc81c\uc2dc\ud558\uba70, \uc11c\ub85c\ub97c \uc874\uc911\ud558\uace0 \uc624\uc9c1 \uc870\uc9c1\uc758 \uc131\uc7a5\uacfc \uc11c\ube44\uc2a4\ub97c \uc704\ud574 \uace0\ubbfc\ud558\uace0 \uc788\ub2e4. \uac00\uc2b4 \ub6f0\ub294 \uc77c\uc774 \uc544\ub2d0 \uc218\uac00 \uc5c6\ub2e4. \ud2b9\ud788, \ub0b4 123\ud559\ub144\uc744 \ube44\uad50\ud558\uba74, \ub098\ub294 \ubd84\uba85, \uc0b4\uc544\uc788\ub2e4\ub294 \uac10\uc815\uc744 \ub290\ub080\ub2e4.\\n\\n\ub0b4\uac00 \uc0dd\uac01\ud55c \uc544\uc774\ub514\uc5b4\ub97c \ubaa8\ub450\uac00 \uac19\uc774 \uac80\uc99d\ud558\uace0, \uac78\uc74c\ub9c8\ub97c \ub744\uc6cc \uc0b4\uc544\uc788\ub294 \ud504\ub85c\ub355\ud2b8\ub85c \ub9cc\ub4e4\uace0 \uc788\ub2e4. \ub2e8\uc21c\ud788 \uc88b\ub2e4\uace0 \ubc1b\uc544\ub4e4\uc774\ub294 \uac83\ub3c4 \uc544\ub2c8\uba70, \uc5c9\ub6b1\ud558\ub2e4\uace0 \uc8fd\uc774\uc9c0\ub3c4 \uc54a\ub294\ub2e4.\\n\\n\ud604\uc7ac \ub9ce\uc740 \uba64\ubc84\ub4e4\uc774 \ud6cc\ub96d\ud55c \uc120\ubc30\ub2d8\ub4e4\uaed8 \uacbd\uc678\uc2ec\uc744 \uac00\uc9c0\uace0 \uc788\ub2e4. \ud558\uc9c0\ub9cc \ud55c \uc120\ubc30\ub97c \uc9c0\ucf1c\ubcf8 \ub098\ub85c\uc11c\ub294, \uadf8 \uc131\uc7a5\uc774 \ud558\ub8e8\uc544\uce68\uc5d0 \uc77c\uc5b4\ub09c \uc77c\ub3c4, \uc2a4\uc2a4\ub85c\ub97c \uace0\ubb38\ud574\uc11c \uc77c\uc5b4\ub09c \uc77c\ub3c4 \uc544\ub2d8\uc744 \uc548\ub2e4. \uc774\uac83\uc774 \ub0b4\uac00 \uc0dd\uac01\ud558\ub294 BCSD Lab\uc758 \uae38\uc774\ub2e4. \ubaa8\ub450\uac00 \uc790\uc2e0\uc774 \uae30\uc5ec\ud55c \ud55c \uc904 \ud55c \uc904\uc774 \ub2e4\ub978 \uc0ac\ub78c\uc73c\ub85c \ud558\uc5ec\uae08 \uc774\ub86d\uace0 \ud3b8\ub9ac\ud558\uace0, \ub098\uc544\uac00 \uc990\uac81\uace0 \ud589\ubcf5\ud558\uac8c \ud574 \uc904 \uc218 \uc788\ub2e4\ub294 \uc0ac\uc2e4\uc744 \ub418\uc0c8\uae30\uba74 \uc88b\uaca0\ub2e4. \uadf8 \uacfc\uc815\uc774 \uaf2d \uafb8\uc900\ud558\uace0 \uc990\uac81\uae38 \ubc14\ub77c\uba70, \ub3cc\uc544\ubd24\uc744 \ub54c \uae30\ubd84 \uc88b\uc740 \uc131\uc7a5 \uacfc\uc815\uc774\uae30\ub97c \ubc14\ub780\ub2e4.\\n\\n\\n\\n\uc5ec\ub7ec\ubd84\ub4e4\uc774 \uadf8\ub7f0 \ud6cc\ub96d\ud55c \uc120\ubc30\uac00 \ub420 \uc218 \uc788\uaca0\ub290\ub0d0 \ubb3b\ub294\ub2e4\uba74 \ub098\ub294 \uc774\ub807\uac8c \ub300\ub2f5\ud558\uace0 \uc2f6\ub2e4.\\n\\n\u201d\uadf8 \uc120\ubc30\uac00 \uc774\ubbf8 \uadf8\ub7f0 \uc9c8\ubb38\uc744 \ud588\uc5c8\ub2e4.\u201d\ub77c\uace0, \uadf8 \uc9c8\ubb38\uc73c\ub85c\uc368 \uc774\ubbf8 \uc131\uc7a5\uc774 \uc2dc\uc791\ub410\ub2e4\uace0.\\n\\n\\n\uc774 \ub9cc\ub0a8\uc774 \ubc18\uac11\uace0, \uae08\ubc29 \uac00\ub4dd \ub118\uccd0\ubc84\ub9ac\ub294 \uc2ac\ub799\uc758 \uc54c\ub9bc\uacfc, ~~\ub04a\uc784\uc5c6\ub294 \ud68c\uc758 \uc77c\uc815\uc774~~ , \uc81c\uac00 \uc62c\ubc14\ub978 \uacf5\ub3d9\uccb4\uc5d0 \uc18d\ud588\ub2e4\ub294 \uc0ac\uc2e4\uc744 \ub290\ub07c\uac8c \ud569\ub2c8\ub2e4. \\n\uc131\uc7a5\uc758 \uae30\uc068\uc744 \uc78a\uc9c0 \uc54a\uace0 \uc5ec\ub7ec\ubd84\ub4e4\uc758 \uc131\uc7a5\uc5d0 \ub3c4\uc6c0\uc774 \ub418\uace0, \ud568\uaed8 \uc2dc\uc57c\ub97c \ub113\ud788\uae30 \uc704\ud574 \ucc38\uc5ec\ud55c PM \uc724\uc6d0\ube48\uc785\ub2c8\ub2e4. \uc55e\uc73c\ub85c \uc798 \ubd80\ud0c1\ub4dc\ub9bd\ub2c8\ub2e4."}]}')}}]);